                {"speaker": "You", "swissGerman": "Hey, chasch mir de Bohrmaschine gäh?", "german": "Hey, kannst du mir die Bohrmaschine geben?", "english": "Hey, can you pass me the drill?", "spanish": "Oye, ¿me pasas el taladro?"},
                {"speaker": "Colleague", "swissGerman": "Weli? D'grossi oder d'chliini?", "german": "Welche? Die große oder die kleine?", "english": "Which one? The big one or the small one?", "spanish": "¿Cuál de los dos? ¿El grande o el pequeño?"},
                {"speaker": "You", "swissGerman": "D'grossi, ich muess es Loch i d'Wand bohre.", "german": "Die große, ich muss ein Loch in die Wand bohren.", "english": "The big one, I need to drill a hole in the wall.", "spanish": "El grande, necesito taladrar un agujero en la pared."},
                {"speaker": "Colleague", "swissGerman": "Da, pass uf! Und nimm de richtig Bohrer, s'isch Beton.", "german": "Da, pass auf! Und nimm den richtigen Bohrer, es ist Beton.", "english": "Here, be careful! And use the right drill bit, it's concrete.", "spanish": "Aquí, ¡ten cuidado! Y usa la broca correcta, es hormigón."},
                {"speaker": "You", "swissGerman": "Ja, ich nimm de Betonbohrer. Merci!", "german": "Ja, ich nehme den Betonbohrer. Danke!", "english": "Yes, I'll use the concrete drill bit. Thanks!", "spanish": "Sí, usaré la broca de hormigón. ¡Gracias!"},
