                {"speaker": "Colleague", "swissGerman": "Gopf, das isch gfährlich! Isch em Thomas öppis passiert?", "german": "Mist, das ist gefährlich! Ist Thomas etwas passiert?", "english": "Damn, that's dangerous! Did anything happen to Thomas?", "spanish": "¡Vaya, eso es peligroso! ¿Le pasó algo a Thomas?"},
                {"speaker": "Foreman", "swissGerman": "Nei, zum Glück nöd. Aber ab hüt: kein Zuegang zum Bau ohni Helm!", "german": "Nein, zum Glück nicht. Aber ab heute: kein Zugang zum Bau ohne Helm!", "english": "No, luckily not. But from today: no access to the site without a helmet!", "spanish": "No, por suerte no. Pero desde hoy: ¡sin casco no se entra a la obra!"},
                {"speaker": "You", "swissGerman": "Absolut richtig. Sicherheit gaht vor.", "german": "Absolut richtig. Sicherheit geht vor.", "english": "Absolutely right. Safety comes first.", "spanish": "Totalmente correcto. La seguridad es lo primero."},
                {"speaker": "Foreman", "swissGerman": "Guet. Ich meld das witerhin em Sicherheitsbeauftragtige.", "german": "Gut. Ich melde das weiters dem Sicherheitsbeauftragten.", "english": "Good. I'll report this further to the safety officer.", "spanish": "Bien. Informaré de esto al responsable de seguridad."},
                {"speaker": "You", "swissGerman": "Richtig. Und mir mached vor de Mittagspuus en kurze Sicherheits-Check.", "german": "Richtig. Und wir machen vor der Mittagspause einen kurzen Sicherheits-Check.", "english": "Right. And we'll do a quick safety check before lunch.", "spanish": "Correcto. Y hacemos una comprobación de seguridad rápida antes de comer."},
